```javascript
var TAU = 6.283;
var GOLDEN_RATIO = 1.618;
var SQRT_HALF = 0.707;

var physicsConfig = {
  attraction: 4000,
  springCoeff: 0.004,
  damping: 0.92,
  centerPull: 0.0003,
  particleMax: 40,
  particleDecay: 0.04,
  cameraSmoothing: 0.06
};

var nodes = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

var springs = [
  { a: 'hub', b: 'alpha',   restLength: 160, stiffness: 0.006 },
  { a: 'hub', b: 'beta',    restLength: 160, stiffness: 0.005 },
  { a: 'hub', b: 'gamma',   restLength: 170, stiffness: 0.004 },
  { a: 'hub', b: 'delta',   restLength: 170, stiffness: 0.004 },
  { a: 'hub', b: 'epsilon', restLength: 180, stiffness: 0.003 },
  { a: 'alpha', b: 'beta',  restLength: 200, stiffness: 0.002 },
  { a: 'gamma', b: 'delta', restLength: 220, stiffness: 0.002 },
  { a: 'alpha', b: 'epsilon', restLength: 200, stiffness: 0.002 }
];

var cameraPosition = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };
var particles = [];
var tickCount = 0;

function findNodeById(nodeId) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === nodeId) return nodes[i];
  }
  return null;
}

function applyForces() {
  // Coulomb repulsion between all node pairs
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var distance = Math.sqrt(dx * dx + dy * dy) || 1;
      var repulsiveForce = physicsConfig.attraction / (distance * distance);
      var forceX = (dx / distance) * repulsiveForce;
      var forceY = (dy / distance) * repulsiveForce;
      nodes[i].vx += forceX;
      nodes[i].vy += forceY;
      nodes[j].vx -= forceX;
      nodes[j].vy -= forceY;
    }
  }

  // Hooke's law spring forces along edges
  for (var s = 0; s < springs.length; s++) {
    var nodeA = findNodeById(springs[s].a);
    var nodeB = findNodeById(springs[s].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var distance = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = distance - springs[s].restLength;
    var springForce = (springs[s].stiffness || physicsConfig.springCoeff) * displacement;
    nodeA.vx += (dx / distance) * springForce;
    nodeA.vy += (dy / distance) * springForce;
    nodeB.vx -= (dx / distance) * springForce;
    nodeB.vy -= (dy / distance) * springForce;
  }

  // Integrate velocity, apply damping, and center-pull gravity
  for (var n = 0; n < nodes.length; n++) {
    nodes[n].vx += (400 - nodes[n].x) * physicsConfig.centerPull;
    nodes[n].vy += (300 - nodes[n].y) * physicsConfig.centerPull;
    nodes[n].vx *= physicsConfig.damping;
    nodes[n].vy *= physicsConfig.damping;
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

function spawnParticle() {
  if (particles.length >= physicsConfig.particleMax) return;
  var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT_HALF;
  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * SQRT_HALF
  });
}

function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var particle = particles[i];
    particle.age++;
    particle.vx *= 1 - physicsConfig.particleDecay * 0.125;
    particle.vy *= 1 - physicsConfig.particleDecay * 0.125;
    particle.x += particle.vx;
    particle.y += particle.vy;
    if (particle.age > particle.maxAge) particles.splice(i, 1);
  }
}

function smoothCamera() {
  cameraPosition.x += (cameraTarget.x - cameraPosition.x) * physicsConfig.cameraSmoothing;
  cameraPosition.y += (cameraTarget.y - cameraPosition.y) * physicsConfig.cameraSmoothing;
  cameraPosition.zoom += (cameraTarget.zoom - cameraPosition.zoom) * physicsConfig.cameraSmoothing;
}

function simulationTick() {
  applyForces();
  updateParticles();
  smoothCamera();
  if (tickCount % 3 === 0) spawnParticle();
  tickCount++;
}

setInterval(simulationTick, 16);
```

